#!/usr/bin/env node
// Generated by claude-sf-toolkit v1.0.0
// Migrates a Salesforce DX project from local skills/agents/scripts to the plugin.
// Archives superseded files, validates health, prints a categorized report.

const fs = require("fs");
const path = require("path");

// ---------------------------------------------------------------------------
// Superseded file manifests
// ---------------------------------------------------------------------------

const SUPERSEDED_SKILLS = [
  "backlog.md",
  "start-day.md",
  "wrap-up.md",
  "skill-preflight.md",
  "lookback.md",
  "deploy-changed.md",
  "devops-commit.md",
  "detect-drift.md",
  "validate-build.md",
  "package-audit.md",
  "test-flows.md",
  "wi-sync.md",
  "release-review.md",
  "doc-flows.md",
  "doc-components.md",
  "platform-review.md",
  "tooling-review.md",
  "design-review.md",
];

const SUPERSEDED_AGENTS = [
  "start-day-git-state.md",
  "start-day-active-work.md",
  "start-day-external-context.md",
];

const PLUGIN_TEMPLATE_SCRIPTS = [
  "backlog-render.js",
  "backlog-validate.js",
  "backlog-stats.js",
  "backlog-add.js",
  "backlog-search.js",
  "metadata-validator.js",
  "drift-compare.js",
  "flow-description-sync.js",
  "flow-index.js",
  "flow-doc-generator.js",
  "flow-changelog-detector.js",
  "platform-review-consolidate.js",
];

const MCP_RETIRED_SCRIPTS = [
  "apex-run.js",
  "sobject-describe.js",
  "list-metadata.js",
  "record-crud.js",
  "platform-brief-audit.js",
];

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function findProjectRoot(startDir) {
  let dir = path.resolve(startDir);
  while (true) {
    if (fs.existsSync(path.join(dir, "sfdx-project.json"))) {
      return dir;
    }
    const parent = path.dirname(dir);
    if (parent === dir) return null; // hit filesystem root
    dir = parent;
  }
}

function datePrefix() {
  const d = new Date();
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const dd = String(d.getDate()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd}`;
}

function ensureDir(dirPath, dryRun) {
  if (!fs.existsSync(dirPath) && !dryRun) {
    fs.mkdirSync(dirPath, { recursive: true });
  }
}

/**
 * Archive a file: copy to archiveDir with date prefix, then remove original.
 * Returns { archived: bool, reason: string }
 */
function archiveFile(srcPath, archiveDir, prefix, dryRun) {
  if (!fs.existsSync(srcPath)) {
    return { archived: false, reason: "not found" };
  }

  const baseName = path.basename(srcPath);
  const archiveName = `${prefix}_${baseName}`;
  const archivePath = path.join(archiveDir, archiveName);

  // Idempotency: if archive already exists with same content, just remove original
  if (fs.existsSync(archivePath)) {
    const srcContent = fs.readFileSync(srcPath);
    const archContent = fs.readFileSync(archivePath);
    if (srcContent.equals(archContent)) {
      if (!dryRun) fs.unlinkSync(srcPath);
      return { archived: true, reason: "already archived (identical), removed original" };
    }
  }

  if (!dryRun) {
    ensureDir(archiveDir, false);
    fs.copyFileSync(srcPath, archivePath);
    fs.unlinkSync(srcPath);
  } else {
    ensureDir(archiveDir, true);
  }

  return { archived: true, reason: "archived" };
}

// ---------------------------------------------------------------------------
// Migration categories
// ---------------------------------------------------------------------------

function migrateCategory(projectRoot, relDir, fileList, archiveSubdir, prefix, dryRun) {
  const sourceDir = path.join(projectRoot, relDir);
  // Archive to project-root .migration-archive/ to avoid Claude Code skill discovery
  // (files inside .claude/commands/_archived/ would be found as slash commands)
  const archiveDir = path.join(projectRoot, ".migration-archive");
  const results = { archived: [], skipped: [], notFound: [] };

  for (const fileName of fileList) {
    const srcPath = path.join(sourceDir, fileName);
    const result = archiveFile(srcPath, archiveDir, prefix, dryRun);

    if (!result.archived && result.reason === "not found") {
      results.notFound.push(fileName);
    } else if (result.archived) {
      results.archived.push(fileName);
    } else {
      results.skipped.push({ file: fileName, reason: result.reason });
    }
  }

  return results;
}

// ---------------------------------------------------------------------------
// Health check
// ---------------------------------------------------------------------------

function healthCheck(projectRoot) {
  const checks = [];

  const required = [
    { file: "sfdx-project.json", label: "SFDX project config" },
  ];

  const recommended = [
    { file: path.join(".sf", "config.json"), label: "SF CLI local config" },
    { file: path.join("config", "sf-toolkit.json"), label: "SF Toolkit config" },
    { file: ".env", label: "Environment variables" },
  ];

  for (const item of required) {
    const exists = fs.existsSync(path.join(projectRoot, item.file));
    checks.push({ ...item, exists, severity: "error" });
  }

  for (const item of recommended) {
    const exists = fs.existsSync(path.join(projectRoot, item.file));
    checks.push({ ...item, exists, severity: "warning" });
  }

  return checks;
}

// ---------------------------------------------------------------------------
// Report
// ---------------------------------------------------------------------------

function printReport(skillResults, agentResults, pluginScriptResults, mcpScriptResults, healthResults, keptFiles, dryRun) {
  const divider = "─".repeat(60);

  if (dryRun) {
    console.log("\n  *** DRY RUN — no files were modified ***\n");
  }

  console.log(divider);
  console.log("  Migration Report");
  console.log(divider);

  // Plugin skills
  console.log("\n  Plugin-superseded skills (.claude/commands/):");
  if (skillResults.archived.length > 0) {
    skillResults.archived.forEach((f) => console.log(`    [archived] ${f}`));
  }
  if (skillResults.notFound.length > 0) {
    skillResults.notFound.forEach((f) => console.log(`    [not found] ${f}`));
  }

  // Plugin agents
  console.log("\n  Plugin-superseded agents (.claude/agents/):");
  if (agentResults.archived.length > 0) {
    agentResults.archived.forEach((f) => console.log(`    [archived] ${f}`));
  }
  if (agentResults.notFound.length > 0) {
    agentResults.notFound.forEach((f) => console.log(`    [not found] ${f}`));
  }

  // Plugin-template scripts
  console.log("\n  Plugin-template-replaced scripts (scripts/):");
  if (pluginScriptResults.archived.length > 0) {
    pluginScriptResults.archived.forEach((f) => console.log(`    [archived] ${f}`));
  }
  if (pluginScriptResults.notFound.length > 0) {
    pluginScriptResults.notFound.forEach((f) => console.log(`    [not found] ${f}`));
  }

  // MCP-retired scripts
  console.log("\n  MCP-retired scripts (scripts/):");
  if (mcpScriptResults.archived.length > 0) {
    mcpScriptResults.archived.forEach((f) => console.log(`    [archived] ${f}`));
  }
  if (mcpScriptResults.notFound.length > 0) {
    mcpScriptResults.notFound.forEach((f) => console.log(`    [not found] ${f}`));
  }

  // Kept files
  if (keptFiles.length > 0) {
    console.log("\n  Kept (not superseded by plugin):");
    keptFiles.forEach((f) => console.log(`    [kept] ${f}`));
  }

  // Health check
  console.log(`\n${divider}`);
  console.log("  Health Check");
  console.log(divider);

  for (const check of healthResults) {
    const icon = check.exists ? "ok" : check.severity === "error" ? "MISSING" : "missing";
    console.log(`    [${icon}] ${check.label} (${check.file})`);
  }

  // Warnings
  const warnings = [];
  const totalArchived =
    skillResults.archived.length +
    agentResults.archived.length +
    pluginScriptResults.archived.length +
    mcpScriptResults.archived.length;

  if (totalArchived === 0) {
    warnings.push("No files were archived — migration may have already been run, or local files do not match expected names.");
  }

  const missingHealth = healthResults.filter((c) => !c.exists && c.severity === "error");
  if (missingHealth.length > 0) {
    warnings.push(`Required config missing: ${missingHealth.map((c) => c.file).join(", ")}`);
  }

  if (warnings.length > 0) {
    console.log(`\n${divider}`);
    console.log("  Warnings");
    console.log(divider);
    warnings.forEach((w) => console.log(`    ! ${w}`));
  }

  // Summary
  console.log(`\n${divider}`);
  console.log("  Summary");
  console.log(divider);
  console.log(`    Archived: ${totalArchived}`);
  console.log(`    Not found: ${skillResults.notFound.length + agentResults.notFound.length + pluginScriptResults.notFound.length + mcpScriptResults.notFound.length}`);
  console.log(`    Kept: ${keptFiles.length}`);
  console.log("");
}

// ---------------------------------------------------------------------------
// Discover kept files (present in source dirs but not on any superseded list)
// ---------------------------------------------------------------------------

function discoverKeptFiles(projectRoot) {
  const kept = [];
  const allSupersededScripts = [...PLUGIN_TEMPLATE_SCRIPTS, ...MCP_RETIRED_SCRIPTS];

  const dirs = [
    { rel: ".claude/commands", superseded: SUPERSEDED_SKILLS },
    { rel: ".claude/agents", superseded: SUPERSEDED_AGENTS },
    { rel: "scripts", superseded: allSupersededScripts },
  ];

  for (const { rel, superseded } of dirs) {
    const dirPath = path.join(projectRoot, rel);
    if (!fs.existsSync(dirPath)) continue;

    const entries = fs.readdirSync(dirPath, { withFileTypes: true });
    for (const entry of entries) {
      if (!entry.isFile()) continue;
      if (entry.name.startsWith(".")) continue;
      if (!superseded.includes(entry.name)) {
        kept.push(path.join(rel, entry.name));
      }
    }
  }

  return kept;
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

function printHelp() {
  console.log(`
Usage: node migrate-from-local.js [options]

Migrates a Salesforce DX project from local skills, agents, and scripts
to the claude-sf-toolkit plugin. Archives superseded files to .migration-archive/
at the project root with a date prefix, then removes the originals.

Options:
  --dry-run   Show what would be done without modifying any files
  --help      Show this help message

The script must be run from within an SFDX project (a directory tree
containing sfdx-project.json). It is idempotent and safe to run
multiple times.

Superseded categories:
  - 18 skills in .claude/commands/
  - 3 agents in .claude/agents/
  - 12 plugin-template-replaced scripts in scripts/
  - 5 MCP-retired scripts in scripts/
`);
}

function main() {
  const args = process.argv.slice(2);

  if (args.includes("--help") || args.includes("-h")) {
    printHelp();
    process.exit(0);
  }

  const dryRun = args.includes("--dry-run");

  // Find project root
  const projectRoot = findProjectRoot(process.cwd());
  if (!projectRoot) {
    console.error("Error: Could not find sfdx-project.json in current or parent directories.");
    console.error("Run this script from within a Salesforce DX project.");
    process.exit(1);
  }

  console.log(`Project root: ${projectRoot}`);
  if (dryRun) {
    console.log("Mode: dry-run (no changes will be made)");
  }

  const prefix = datePrefix();

  // Migrate each category
  const skillResults = migrateCategory(
    projectRoot,
    ".claude/commands",
    SUPERSEDED_SKILLS,
    "_archived",
    prefix,
    dryRun
  );

  const agentResults = migrateCategory(
    projectRoot,
    ".claude/agents",
    SUPERSEDED_AGENTS,
    "_archived",
    prefix,
    dryRun
  );

  const pluginScriptResults = migrateCategory(
    projectRoot,
    "scripts",
    PLUGIN_TEMPLATE_SCRIPTS,
    "_archived",
    prefix,
    dryRun
  );

  const mcpScriptResults = migrateCategory(
    projectRoot,
    "scripts",
    MCP_RETIRED_SCRIPTS,
    "_archived",
    prefix,
    dryRun
  );

  // Discover kept files
  const keptFiles = discoverKeptFiles(projectRoot);

  // Health check
  const healthResults = healthCheck(projectRoot);

  // Report
  printReport(
    skillResults,
    agentResults,
    pluginScriptResults,
    mcpScriptResults,
    healthResults,
    keptFiles,
    dryRun
  );
}

main();
